    )]
    Update {
        #[arg(help = "ID of the time entry to edit")]
        id: Option<i64>,
        #[arg(short, long, help = "Edit the currently running time entry")]
        current: bool,
        #[arg(short, long, help = "New description")]
        description: Option<String>,
        #[arg(long, help = "New billable state (true/false)")]
