use std::collections::HashMap;

use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities;

pub struct StatsCommand;

fn project_totals(entries: &[TimeEntry]) -> Vec<(String, i64)> {
    let mut totals: HashMap<String, i64> = HashMap::new();

    for entry in entries.iter().filter(|entry| !entry.is_running()) {
        let project_name = entry
            .project
            .as_ref()
            .map(|project| project.name.clone())
            .unwrap_or_else(|| "No Project".to_string());
        *totals.entry(project_name).or_default() += entry.duration;
    }

    let mut totals: Vec<_> = totals.into_iter().collect();
    totals.sort_by(|(left_name, left_duration), (right_name, right_duration)| {
        right_duration
            .cmp(left_duration)
            .then_with(|| left_name.cmp(right_name))
    });

    totals
}

fn total_seconds(totals: &[(String, i64)]) -> i64 {
    totals.iter().map(|(_, duration)| duration).sum()
}

fn summarize(entries: &[TimeEntry]) -> String {
    let totals = project_totals(entries);
    let total_seconds = total_seconds(&totals);
    let mut output = totals
        .into_iter()
        .map(|(name, duration)| format!("{}  {name}", utilities::format_duration_compact(duration)))
        .collect::<Vec<_>>();
    output.push(format!(
        "{}  Total",
        utilities::format_duration_compact(total_seconds)
    ));
    output.join("\n")
}

fn summarize_json(entries: &[TimeEntry]) -> String {
    let totals = project_totals(entries);
    let groups: Vec<_> = totals
        .iter()
        .map(|(project, seconds)| {
            serde_json::json!({
                "project": project,
                "seconds": seconds,
            })
        })
        .collect();
    serde_json::json!({
        "groups": groups,
        "total_seconds": total_seconds(&totals),
    })
    .to_string()
}

impl StatsCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
        json: bool,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = utilities::normalize_time_entry_list_filters(since, until)?;
        let entries = api_client.get_time_entries_filtered(since, until).await?;
        if json {
            println!("{}", summarize_json(&entries));
        } else {
            println!("{}", summarize(&entries));
        }
        Ok(())
    }
}

